import type { Metadata } from "next";
import ExpenseReport from "./ExpenseReport";

export const metadata: Metadata = {
  title: "経費精算申請 | ぐんじょう会計",
  description:
    "経費精算の申請画面。日付・利用先・勘定科目・税区分（10% / 軽減8% / 非課税）・金額（税込）・領収書を明細ごとに入力し、合計金額と税区分別の内税を自動計算。規定上限超過や領収書未添付の規定チェック警告に対応し、申請者 → 一次承認（上長） → 経理の承認ワークフロー（申請 / 取消 / 承認 / 差戻し）を備えた経費精算ツールです。",
};

export default function ExpensePage() {
  return <ExpenseReport />;
}

"use client";

import * as React from "react";
import {
  Timeline,
  TimelineItem,
  TimelineTitle,
  TimelineDescription,
  TimelineTime,
  Badge,
} from "@gunjo/ui";
import {
  IconCheck,
  IconClockHour4,
  IconArrowBackUp,
  IconUser,
  type Icon,
} from "@tabler/icons-react";
import {
  type ApprovalStep,
  type StepState,
  STEP_STATE_LABEL,
} from "./expense-data";

type BadgeVariant = "success" | "warning" | "info" | "secondary";

const STATE_META: Record<
  StepState,
  { icon: Icon; badge: BadgeVariant; marker: "default" | "muted" | "active" }
> = {
  done: { icon: IconCheck, badge: "success", marker: "default" },
  current: { icon: IconClockHour4, badge: "info", marker: "active" },
  rejected: { icon: IconArrowBackUp, badge: "warning", marker: "default" },
  waiting: { icon: IconUser, badge: "secondary", marker: "muted" },
};

export function ApprovalRoute({ steps }: { steps: ApprovalStep[] }) {
  return (
    <Timeline aria-label="承認経路">
      {steps.map((step, i) => {
        const meta = STATE_META[step.state];
        const MarkerIcon = meta.icon;
        const isLast = i === steps.length - 1;
        // Color the marker icon by tone without relying on colour alone — the
        // Badge text below carries the same state in words.
        const toneClass =
          step.state === "done"
            ? "text-success"
            : step.state === "current"
              ? "text-info"
              : step.state === "rejected"
                ? "text-warning"
                : "text-muted-foreground";
        return (
          <TimelineItem
            key={step.id}
            connector={!isLast}
            variant={meta.marker}
            marker={
              <span
                className={`flex h-5 w-5 items-center justify-center rounded-full border bg-background ${toneClass}`}
              >
                <MarkerIcon className="h-3.5 w-3.5" aria-hidden />
              </span>
            }
          >
            <div className="flex flex-wrap items-center gap-x-2 gap-y-1">
              <TimelineTitle>{step.role}</TimelineTitle>
              <Badge variant={meta.badge} className="gap-1">
                <MarkerIcon className="h-3 w-3" aria-hidden />
                {STEP_STATE_LABEL[step.state]}
              </Badge>
            </div>
            <TimelineDescription>{step.actor}</TimelineDescription>
            {step.at ? (
              <TimelineTime dateTime={step.at}>{step.at}</TimelineTime>
            ) : null}
            {step.comment ? (
              <p className="mt-1 rounded-md border border-warning-border bg-warning-subtle px-2 py-1 text-xs text-warning-subtle-foreground">
                コメント：{step.comment}
              </p>
            ) : null}
          </TimelineItem>
        );
      })}
    </Timeline>
  );
}

// 経費精算申請 — domain data, pure helpers. No React here.

export type TaxRate = "10" | "8" | "0"; // 10% / 軽減8% / 非課税(0%)

export interface TaxCategory {
  id: TaxRate;
  label: string; // shown in the select
  rate: number; // 0.10 / 0.08 / 0
}

export const TAX_CATEGORIES: TaxCategory[] = [
  { id: "10", label: "課税 10%", rate: 0.1 },
  { id: "8", label: "軽減 8%", rate: 0.08 },
  { id: "0", label: "非課税", rate: 0 },
];

export function taxById(id: TaxRate): TaxCategory {
  return TAX_CATEGORIES.find((t) => t.id === id) ?? TAX_CATEGORIES[0];
}

export interface ExpenseCategory {
  id: string;
  label: string;
  /** 規定上限(円)。超えると規定チェックで警告。未設定なら上限なし。 */
  limit?: number;
}

// 勘定科目マスタ（経費精算でよく使う科目に絞る）
export const EXPENSE_CATEGORIES: ExpenseCategory[] = [
  { id: "travel", label: "旅費交通費", limit: 10000 },
  { id: "entertainment", label: "接待交際費", limit: 30000 },
  { id: "supplies", label: "消耗品費" },
  { id: "communication", label: "通信費" },
  { id: "books", label: "新聞図書費" },
  { id: "meeting", label: "会議費", limit: 5000 },
  { id: "misc", label: "雑費" },
];

export function categoryById(id: string): ExpenseCategory | undefined {
  return EXPENSE_CATEGORIES.find((c) => c.id === id);
}

export type SettlementMethod = "transfer" | "cash" | "corporate-card";

export const SETTLEMENT_METHODS: { id: SettlementMethod; label: string }[] = [
  { id: "transfer", label: "振込" },
  { id: "cash", label: "現金" },
  { id: "corporate-card", label: "法人カード" },
];

export function settlementLabel(id: SettlementMethod): string {
  return SETTLEMENT_METHODS.find((m) => m.id === id)?.label ?? id;
}

// 領収書 — per-line attachment (we only keep light metadata, not the File blob).
export interface ReceiptMeta {
  name: string;
  size: number; // bytes
}

export interface ExpenseLine {
  id: string;
  date: string; // yyyy-mm-dd
  merchant: string; // 利用先
  categoryId: string; // 勘定科目
  tax: TaxRate; // 税区分
  amount: number; // 金額(税込, 円)
  receipt?: ReceiptMeta; // 領収書
}

let lineSeq = 0;
export function createEmptyLine(): ExpenseLine {
  lineSeq += 1;
  return {
    id: `line-${Date.now()}-${lineSeq}`,
    date: "",
    merchant: "",
    categoryId: "",
    tax: "10",
    amount: 0,
    receipt: undefined,
  };
}

export function seedLines(): ExpenseLine[] {
  return [
    {
      id: "seed-1",
      date: "2026-06-03",
      merchant: "JR東日本（新宿→品川）",
      categoryId: "travel",
      tax: "10",
      amount: 8420,
      receipt: { name: "ic-2026-06-03.pdf", size: 48211 },
    },
    {
      id: "seed-2",
      date: "2026-06-05",
      merchant: "スターバックス 品川店",
      categoryId: "meeting",
      tax: "8",
      amount: 3960,
      receipt: { name: "receipt-starbucks.jpg", size: 132044 },
    },
    {
      id: "seed-3",
      date: "2026-06-11",
      merchant: "ヨドバシカメラ（USBハブ）",
      categoryId: "supplies",
      tax: "10",
      amount: 2980,
      receipt: undefined,
    },
  ];
}

// ---- money ----

/** 税込金額から内消費税を逆算する。 */
export function taxIncludedPortion(amount: number, rate: number): number {
  if (rate <= 0) return 0;
  return Math.round((amount * rate) / (1 + rate));
}

export interface Totals {
  total: number; // 合計(税込)
  byRate: { id: TaxRate; label: string; net: number; tax: number; gross: number }[];
}

export function computeTotals(lines: ExpenseLine[]): Totals {
  const total = lines.reduce((sum, l) => sum + (l.amount || 0), 0);
  const byRate = TAX_CATEGORIES.map((cat) => {
    const gross = lines
      .filter((l) => l.tax === cat.id)
      .reduce((s, l) => s + (l.amount || 0), 0);
    const tax = taxIncludedPortion(gross, cat.rate);
    return { id: cat.id, label: cat.label, net: gross - tax, tax, gross };
  }).filter((r) => r.gross !== 0);
  return { total, byRate };
}

// ---- validation (per line) ----

export function lineHasContent(l: ExpenseLine): boolean {
  return Boolean(l.merchant.trim() || l.categoryId || l.amount > 0 || l.date);
}

/** Blocking errors — submission is disabled while any line returns a message. */
export function validateLine(l: ExpenseLine): string | undefined {
  if (!lineHasContent(l)) return undefined; // a wholly-empty row isn't an error yet
  const missing: string[] = [];
  if (!l.date) missing.push("日付");
  if (!l.categoryId) missing.push("勘定科目");
  if (!(l.amount > 0)) missing.push("金額");
  if (missing.length) return `${missing.join("・")}を入力してください`;
  return undefined;
}

// ---- 規定チェック (policy) — non-blocking warnings ----

export interface PolicyWarning {
  lineId: string;
  lineIndex: number;
  message: string;
}

export function policyWarnings(lines: ExpenseLine[]): PolicyWarning[] {
  const out: PolicyWarning[] = [];
  lines.forEach((l, i) => {
    if (!lineHasContent(l)) return;
    const cat = categoryById(l.categoryId);
    if (cat?.limit && l.amount > cat.limit) {
      out.push({
        lineId: l.id,
        lineIndex: i,
        message: `明細${i + 1}：${cat.label}が規定上限 ${formatYen(cat.limit)} を超えています（${formatYen(l.amount)}）`,
      });
    }
    if (!l.receipt && l.amount > 3000) {
      out.push({
        lineId: l.id,
        lineIndex: i,
        message: `明細${i + 1}：${formatYen(3000)} 超の経費には領収書の添付が必要です`,
      });
    }
  });
  return out;
}

// tiny local yen helper for plain-string messages (component uses @gunjo/ui formatCurrency for display)
function formatYen(n: number): string {
  return `¥${n.toLocaleString("ja-JP")}`;
}

// ---- approval workflow ----

export type ExpenseStatus = "draft" | "submitted" | "approved" | "rejected";

export const STATUS_LABEL: Record<ExpenseStatus, string> = {
  draft: "下書き",
  submitted: "申請中",
  approved: "承認済み",
  rejected: "差戻し",
};

export type StepState = "done" | "current" | "waiting" | "rejected";

export interface ApprovalStep {
  id: string;
  role: string; // 申請者 / 一次承認(上長) / 経理
  actor: string; // person name
  state: StepState;
  at?: string; // timestamp display
  comment?: string;
}

export function initialRoute(applicant: string): ApprovalStep[] {
  return [
    { id: "applicant", role: "申請者", actor: applicant, state: "waiting" },
    { id: "manager", role: "一次承認（上長）", actor: "佐藤 部長", state: "waiting" },
    { id: "accounting", role: "経理", actor: "経理部 山田", state: "waiting" },
  ];
}

export const STEP_STATE_LABEL: Record<StepState, string> = {
  done: "承認",
  current: "承認待ち",
  waiting: "待ち",
  rejected: "差戻し",
};

"use client";

import * as React from "react";
import {
  EditableDataTable,
  type EditableColumn,
  Input,
  NumberInput,
  Select,
  Button,
  Badge,
  formatCurrency,
} from "@gunjo/ui";
import { IconPaperclip, IconCheck, IconX } from "@tabler/icons-react";
import {
  type ExpenseLine,
  type TaxRate,
  EXPENSE_CATEGORIES,
  TAX_CATEGORIES,
  validateLine,
  type Totals,
} from "./expense-data";

interface Props {
  lines: ExpenseLine[];
  totals: Totals;
  readOnly: boolean;
  onPatch: (id: string, patch: Partial<ExpenseLine>) => void;
  onAdd: () => void;
  onRemove: (index: number) => void;
  onAttach: (id: string, file: File | null) => void;
  /** line ids that have an active policy warning (for the receipt cell hint) */
  warnLineIds: Set<string>;
}

function fileKb(size: number): string {
  return `${Math.max(1, Math.round(size / 1024))} KB`;
}

export function ExpenseLineGrid({
  lines,
  totals,
  readOnly,
  onPatch,
  onAdd,
  onRemove,
  onAttach,
  warnLineIds,
}: Props) {
  // one hidden file input per row, keyed by line id
  const fileInputs = React.useRef<Record<string, HTMLInputElement | null>>({});

  const columns: EditableColumn<ExpenseLine>[] = [
    {
      id: "date",
      header: "日付",
      width: "9rem",
      cell: (row, ctx) =>
        readOnly ? (
          <span className="tabular-nums">{row.date || "—"}</span>
        ) : (
          <Input
            type="date"
            aria-label={ctx.ariaLabel}
            value={row.date}
            onChange={(e) => onPatch(row.id, { date: e.target.value })}
          />
        ),
    },
    {
      id: "merchant",
      header: "利用先",
      width: "13rem",
      cellClassName: "min-w-[10rem]",
      cell: (row, ctx) =>
        readOnly ? (
          <span>{row.merchant || "—"}</span>
        ) : (
          <Input
            aria-label={ctx.ariaLabel}
            placeholder="例）JR東日本"
            value={row.merchant}
            onChange={(e) => onPatch(row.id, { merchant: e.target.value })}
          />
        ),
    },
    {
      id: "category",
      header: "勘定科目",
      width: "9.5rem",
      cell: (row, ctx) =>
        readOnly ? (
          <span>
            {EXPENSE_CATEGORIES.find((c) => c.id === row.categoryId)?.label || "—"}
          </span>
        ) : (
          <Select
            aria-label={ctx.ariaLabel}
            value={row.categoryId}
            onChange={(e) => onPatch(row.id, { categoryId: e.target.value })}
          >
            <option value="">選択</option>
            {EXPENSE_CATEGORIES.map((c) => (
              <option key={c.id} value={c.id}>
                {c.label}
              </option>
            ))}
          </Select>
        ),
    },
    {
      id: "tax",
      header: "税区分",
      width: "7.5rem",
      cell: (row, ctx) =>
        readOnly ? (
          <span>{TAX_CATEGORIES.find((t) => t.id === row.tax)?.label}</span>
        ) : (
          <Select
            aria-label={ctx.ariaLabel}
            value={row.tax}
            onChange={(e) =>
              onPatch(row.id, { tax: e.target.value as TaxRate })
            }
          >
            {TAX_CATEGORIES.map((t) => (
              <option key={t.id} value={t.id}>
                {t.label}
              </option>
            ))}
          </Select>
        ),
    },
    {
      id: "amount",
      header: "金額",
      align: "right",
      width: "8.5rem",
      cell: (row, ctx) =>
        readOnly ? (
          <span className="tabular-nums">{formatCurrency(row.amount)}</span>
        ) : (
          <NumberInput
            aria-label={ctx.ariaLabel}
            className="text-right tabular-nums"
            value={row.amount}
            min={0}
            step={100}
            onValueChange={(v) => onPatch(row.id, { amount: v })}
          />
        ),
    },
    {
      id: "receipt",
      header: "領収書",
      width: "11rem",
      cell: (row, ctx) => {
        const needsReceipt = !row.receipt && warnLineIds.has(row.id);
        if (row.receipt) {
          return (
            <div className="flex items-center gap-1.5">
              <Badge variant="success" className="shrink-0 gap-1">
                <IconCheck className="h-3 w-3" aria-hidden />
                添付済
              </Badge>
              <span
                className="min-w-0 max-w-[7rem] truncate text-xs text-muted-foreground"
                title={`${row.receipt.name}（${fileKb(row.receipt.size)}）`}
              >
                {row.receipt.name}（{fileKb(row.receipt.size)}）
              </span>
              {!readOnly && (
                <Button
                  type="button"
                  variant="ghost"
                  size="icon"
                  className="h-7 w-7 shrink-0"
                  aria-label={`${ctx.ariaLabel} を削除`}
                  onClick={() => onAttach(row.id, null)}
                >
                  <IconX className="h-3.5 w-3.5" aria-hidden />
                </Button>
              )}
            </div>
          );
        }
        if (readOnly) {
          return (
            <span className="text-xs text-muted-foreground">未添付</span>
          );
        }
        return (
          <div className="flex flex-col gap-1">
            <input
              ref={(el) => {
                fileInputs.current[row.id] = el;
              }}
              type="file"
              accept="image/*,application/pdf"
              className="sr-only"
              aria-label={ctx.ariaLabel}
              onChange={(e) =>
                onAttach(row.id, e.target.files?.[0] ?? null)
              }
            />
            <Button
              type="button"
              variant="outline"
              size="sm"
              aria-label={`${ctx.ariaLabel}を添付`}
              onClick={() => fileInputs.current[row.id]?.click()}
            >
              <IconPaperclip className="h-3.5 w-3.5" aria-hidden />
              添付
            </Button>
            {needsReceipt && (
              <span className="text-[11px] font-medium text-warning">
                ¥3,000超は領収書必須
              </span>
            )}
          </div>
        );
      },
    },
  ];

  const footer = (
    <div className="flex flex-wrap items-center justify-between gap-2">
      <div className="flex flex-wrap items-center gap-x-4 gap-y-1 text-xs text-muted-foreground">
        {totals.byRate.length === 0 ? (
          <span>税区分別の内訳はありません</span>
        ) : (
          totals.byRate.map((r) => (
            <span key={r.id} className="tabular-nums">
              {r.label}：{formatCurrency(r.gross)}
              <span className="ml-1 opacity-70">
                (内税 {formatCurrency(r.tax)})
              </span>
            </span>
          ))
        )}
      </div>
      <div className="flex items-baseline gap-2">
        <span className="text-sm text-muted-foreground">合計金額</span>
        <span className="text-lg font-semibold tabular-nums text-foreground">
          {formatCurrency(totals.total)}
        </span>
      </div>
    </div>
  );

  return (
    <EditableDataTable<ExpenseLine>
      columns={columns}
      rows={lines}
      getRowId={(row) => row.id}
      onAddRow={readOnly ? undefined : onAdd}
      onRemoveRow={readOnly ? undefined : onRemove}
      minRows={0}
      getRowError={(row) => validateLine(row)}
      rowLabel={(i) => `明細${i + 1}`}
      footer={footer}
      labels={{
        addRow: "明細を追加",
        removeRow: (i) => `明細${i + 1}を削除`,
        empty: (
          <span className="text-sm text-muted-foreground">
            経費明細がありません。「明細を追加」から1行目を入力してください。
          </span>
        ),
      }}
      caption={
        readOnly
          ? "経費明細（閲覧）"
          : "経費明細 — 各行の金額は税込で入力してください"
      }
    />
  );
}

"use client";

import * as React from "react";
import {
  Card,
  CardHeader,
  CardTitle,
  CardDescription,
  CardContent,
  Button,
  Input,
  Select,
  Badge,
  Separator,
  Statistic,
  Alert,
  AlertTitle,
  AlertDescription,
  Form,
  FormField,
  FormLabel,
  FormControl,
  FormMessage,
  Textarea,
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
  formatCurrency,
} from "@gunjo/ui";
import {
  IconCheck,
  IconClockHour4,
  IconArrowBackUp,
  IconPencil,
  IconSend,
  IconAlertTriangle,
  IconUserCheck,
  IconReceipt,
} from "@tabler/icons-react";
import {
  type ExpenseLine,
  type ExpenseStatus,
  type SettlementMethod,
  type ApprovalStep,
  type ReceiptMeta,
  SETTLEMENT_METHODS,
  STATUS_LABEL,
  seedLines,
  createEmptyLine,
  computeTotals,
  validateLine,
  lineHasContent,
  policyWarnings,
  initialRoute,
} from "./expense-data";
import { ExpenseLineGrid } from "./ExpenseLineGrid";
import { ApprovalRoute } from "./ApprovalRoute";

type Role = "applicant" | "approver";

const APPLICANT = "田中 太郎";
const MANAGER = "佐藤 部長";

function nowStamp(): string {
  const d = new Date();
  const p = (n: number) => String(n).padStart(2, "0");
  return `2026-06-23 ${p(d.getHours())}:${p(d.getMinutes())}`;
}

const STATUS_META: Record<
  ExpenseStatus,
  {
    variant: "secondary" | "info" | "success" | "warning";
    icon: typeof IconCheck;
  }
> = {
  draft: { variant: "secondary", icon: IconPencil },
  submitted: { variant: "info", icon: IconClockHour4 },
  approved: { variant: "success", icon: IconCheck },
  rejected: { variant: "warning", icon: IconArrowBackUp },
};

export default function ExpenseReport() {
  // ---- header ----
  const [title, setTitle] = React.useState("6月度 出張・会議費の精算");
  const [titleTouched, setTitleTouched] = React.useState(false);
  const [method, setMethod] = React.useState<SettlementMethod>("transfer");
  const applyDate = "2026-06-22";

  // ---- lines ----
  const [lines, setLines] = React.useState<ExpenseLine[]>(seedLines);

  // ---- workflow ----
  const [status, setStatus] = React.useState<ExpenseStatus>("draft");
  const [route, setRoute] = React.useState<ApprovalStep[]>(
    initialRoute(APPLICANT)
  );
  const [role, setRole] = React.useState<Role>("applicant");

  // ---- 差戻し dialog ----
  const [rejectOpen, setRejectOpen] = React.useState(false);
  const [rejectComment, setRejectComment] = React.useState("");
  const [rejectError, setRejectError] = React.useState<string | undefined>();

  // a polite live-region for status transitions (announced, not colour-only)
  const [announce, setAnnounce] = React.useState("");

  const editable = status === "draft" || status === "rejected";

  const totals = React.useMemo(() => computeTotals(lines), [lines]);
  const warnings = React.useMemo(() => policyWarnings(lines), [lines]);
  const warnLineIds = React.useMemo(
    () => new Set(warnings.map((w) => w.lineId)),
    [warnings]
  );

  const filledLines = lines.filter(lineHasContent);
  const lineErrors = filledLines
    .map((l) => validateLine(l))
    .filter(Boolean) as string[];
  const titleMissing = title.trim() === "";
  const canSubmit =
    editable &&
    filledLines.length > 0 &&
    lineErrors.length === 0 &&
    !titleMissing;

  // ---- line ops ----
  const patchLine = (id: string, patch: Partial<ExpenseLine>) =>
    setLines((prev) =>
      prev.map((l) => (l.id === id ? { ...l, ...patch } : l))
    );
  const addLine = () => setLines((prev) => [...prev, createEmptyLine()]);
  const removeLine = (index: number) =>
    setLines((prev) => prev.filter((_, i) => i !== index));
  const attachReceipt = (id: string, file: File | null) => {
    const receipt: ReceiptMeta | undefined = file
      ? { name: file.name, size: file.size }
      : undefined;
    patchLine(id, { receipt });
  };

  // ---- workflow transitions ----
  function submit() {
    setTitleTouched(true);
    if (!canSubmit) {
      setAnnounce("申請できません。未入力の項目があります。");
      return;
    }
    const stamp = nowStamp();
    setStatus("submitted");
    setRoute([
      { id: "applicant", role: "申請者", actor: APPLICANT, state: "done", at: stamp, comment: undefined },
      { id: "manager", role: "一次承認（上長）", actor: MANAGER, state: "current" },
      { id: "accounting", role: "経理", actor: "経理部 山田", state: "waiting" },
    ]);
    setRole("approver");
    setAnnounce(`ステータスを「申請中」に更新しました。${MANAGER}の承認待ちです。`);
  }

  function cancelApplication() {
    setStatus("draft");
    setRoute(initialRoute(APPLICANT));
    setRole("applicant");
    setAnnounce("申請を取消し、下書きに戻しました。");
  }

  function approve() {
    const stamp = nowStamp();
    setStatus("approved");
    setRoute((prev) =>
      prev.map((s) => {
        if (s.id === "manager")
          return { ...s, state: "done", at: stamp };
        if (s.id === "accounting")
          return { ...s, state: "done", at: stamp };
        return s;
      })
    );
    setAnnounce("ステータスを「承認済み」に更新しました。");
  }

  function openReject() {
    setRejectComment("");
    setRejectError(undefined);
    setRejectOpen(true);
  }

  function confirmReject() {
    if (rejectComment.trim() === "") {
      setRejectError("差戻しの理由（コメント）を入力してください");
      return;
    }
    const stamp = nowStamp();
    setStatus("rejected");
    setRoute((prev) =>
      prev.map((s) =>
        s.id === "manager"
          ? { ...s, state: "rejected", at: stamp, comment: rejectComment.trim() }
          : s
      )
    );
    setRejectOpen(false);
    setRole("applicant");
    setAnnounce("ステータスを「差戻し」に更新しました。申請者に差し戻されました。");
  }

  const statusMeta = STATUS_META[status];
  const StatusIcon = statusMeta.icon;

  return (
    <main className="mx-auto w-full max-w-5xl px-4 py-6 sm:px-6 sm:py-8">
      {/* polite live region for status transitions */}
      <div className="sr-only" role="status" aria-live="polite">
        {announce}
      </div>

      {/* ---- page header ---- */}
      <div className="mb-6 flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
        <div className="flex flex-col gap-1">
          <h1 className="flex items-center gap-2 text-2xl font-semibold tracking-tight text-foreground">
            <IconReceipt className="h-6 w-6 text-muted-foreground" aria-hidden />
            経費精算申請
          </h1>
          <p className="text-sm text-muted-foreground">
            経費明細を入力し、上長 → 経理の承認ワークフローへ申請します。
          </p>
        </div>
        <div className="flex items-center gap-3">
          {/* role switch — demo affordance to see both views */}
          <label className="flex items-center gap-2 text-xs text-muted-foreground">
            <span>表示</span>
            <Select
              aria-label="表示する役割"
              value={role}
              onChange={(e) => setRole(e.target.value as Role)}
              className="h-8 w-auto"
            >
              <option value="applicant">申請者の画面</option>
              <option value="approver">承認者（上長）の画面</option>
            </Select>
          </label>
          <Badge
            variant={statusMeta.variant}
            className="h-7 gap-1.5 px-3 text-sm"
            aria-label={`ステータス：${STATUS_LABEL[status]}`}
          >
            <StatusIcon className="h-4 w-4" aria-hidden />
            {STATUS_LABEL[status]}
          </Badge>
        </div>
      </div>

      <div className="flex flex-col gap-6">
        {/* ---- 申請ヘッダ ---- */}
        <Card>
          <CardHeader>
            <CardTitle as="h2">申請内容</CardTitle>
            <CardDescription>
              申請者・申請日・件名・精算方法を確認してください。
            </CardDescription>
          </CardHeader>
          <CardContent>
            <Form
              onSubmit={(e) => {
                e.preventDefault();
                submit();
              }}
            >
              <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
                <FormField>
                  <FormLabel>申請者</FormLabel>
                  <FormControl>
                    <Input value={APPLICANT} readOnly aria-readonly />
                  </FormControl>
                </FormField>

                <FormField>
                  <FormLabel>申請日</FormLabel>
                  <FormControl>
                    <Input value={applyDate} readOnly aria-readonly />
                  </FormControl>
                </FormField>

                <FormField
                  required
                  error={
                    (titleTouched || status !== "draft") && titleMissing
                      ? "件名／プロジェクトを入力してください"
                      : undefined
                  }
                >
                  <FormLabel>件名／プロジェクト</FormLabel>
                  <FormControl>
                    <Input
                      value={title}
                      disabled={!editable}
                      onChange={(e) => setTitle(e.target.value)}
                      onBlur={() => setTitleTouched(true)}
                      placeholder="例）6月度 出張・会議費の精算"
                    />
                  </FormControl>
                  <FormMessage />
                </FormField>

                <FormField>
                  <FormLabel>精算方法</FormLabel>
                  <FormControl>
                    <Select
                      value={method}
                      disabled={!editable}
                      onChange={(e) =>
                        setMethod(e.target.value as SettlementMethod)
                      }
                    >
                      {SETTLEMENT_METHODS.map((m) => (
                        <option key={m.id} value={m.id}>
                          {m.label}
                        </option>
                      ))}
                    </Select>
                  </FormControl>
                </FormField>
              </div>
            </Form>

            <Separator className="my-5" />

            <div className="flex flex-wrap gap-6">
              <Statistic label="合計金額" value={formatCurrency(totals.total)} />
              <Statistic
                label="明細件数"
                value={`${filledLines.length} 件`}
              />
              <Statistic
                label="領収書"
                value={`${filledLines.filter((l) => l.receipt).length} / ${filledLines.length} 添付`}
              />
            </div>
          </CardContent>
        </Card>

        {/* ---- 規定チェック (policy) ---- */}
        {warnings.length > 0 && (
          <Alert variant="warning">
            <IconAlertTriangle className="h-4 w-4" aria-hidden />
            <AlertTitle as="h2">規定チェックの警告（{warnings.length}件）</AlertTitle>
            <AlertDescription>
              <ul className="list-disc space-y-0.5 pl-4">
                {warnings.map((w, i) => (
                  <li key={`${w.lineId}-${i}`}>{w.message}</li>
                ))}
              </ul>
            </AlertDescription>
          </Alert>
        )}

        {/* ---- validation summary ---- */}
        {(titleTouched || status !== "draft") &&
          editable &&
          (lineErrors.length > 0 || filledLines.length === 0) && (
            <Alert variant="destructive">
              <IconAlertTriangle className="h-4 w-4" aria-hidden />
              <AlertTitle as="h2">申請前に修正してください</AlertTitle>
              <AlertDescription>
                <ul className="list-disc space-y-0.5 pl-4">
                  {filledLines.length === 0 && (
                    <li>経費明細を1行以上入力してください。</li>
                  )}
                  {lineErrors.map((e, i) => (
                    <li key={i}>{e}</li>
                  ))}
                </ul>
              </AlertDescription>
            </Alert>
          )}

        {/* ---- 経費明細 ---- */}
        <Card>
          <CardHeader>
            <CardTitle as="h2">経費明細</CardTitle>
            <CardDescription>
              日付・利用先・勘定科目・税区分・金額（税込）と領収書を行ごとに入力します。
              {!editable && "（申請中・承認後は閲覧のみ）"}
            </CardDescription>
          </CardHeader>
          <CardContent>
            <ExpenseLineGrid
              lines={lines}
              totals={totals}
              readOnly={!editable}
              onPatch={patchLine}
              onAdd={addLine}
              onRemove={removeLine}
              onAttach={attachReceipt}
              warnLineIds={warnLineIds}
            />
          </CardContent>
        </Card>

        {/* ---- 承認経路 ---- */}
        <Card>
          <CardHeader>
            <CardTitle as="h2">承認経路</CardTitle>
            <CardDescription>
              申請者 → 一次承認（上長） → 経理 の各ステップの状態です。
            </CardDescription>
          </CardHeader>
          <CardContent>
            <ApprovalRoute steps={route} />
          </CardContent>
        </Card>

        {/* ---- action bar ---- */}
        <div className="sticky bottom-0 z-10 -mx-4 border-t border-border bg-background/95 px-4 py-3 backdrop-blur sm:-mx-6 sm:px-6">
          <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
            <p className="text-sm text-muted-foreground">
              {role === "approver"
                ? "承認者として操作しています。"
                : "申請者として操作しています。"}
            </p>
            <div className="flex flex-wrap items-center gap-2">
              {role === "applicant" ? (
                <>
                  {(status === "submitted") && (
                    <Button variant="outline" onClick={cancelApplication}>
                      申請を取消
                    </Button>
                  )}
                  <Button
                    variant="primary"
                    onClick={submit}
                    disabled={!canSubmit}
                  >
                    <IconSend className="h-4 w-4" aria-hidden />
                    {status === "rejected" ? "再申請する" : "申請する"}
                  </Button>
                </>
              ) : (
                <>
                  <Button
                    variant="warning"
                    onClick={openReject}
                    disabled={status !== "submitted"}
                  >
                    <IconArrowBackUp className="h-4 w-4" aria-hidden />
                    差戻し
                  </Button>
                  <Button
                    variant="success"
                    onClick={approve}
                    disabled={status !== "submitted"}
                  >
                    <IconUserCheck className="h-4 w-4" aria-hidden />
                    承認する
                  </Button>
                </>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* ---- 差戻し dialog (comment required) ---- */}
      <Dialog open={rejectOpen} onOpenChange={setRejectOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>差戻し</DialogTitle>
            <DialogDescription>
              申請者に差し戻します。理由を入力してください（必須）。
            </DialogDescription>
          </DialogHeader>
          <FormField required error={rejectError}>
            <FormLabel>差戻しコメント</FormLabel>
            <FormControl>
              <Textarea
                value={rejectComment}
                onChange={(e) => {
                  setRejectComment(e.target.value);
                  if (rejectError && e.target.value.trim()) setRejectError(undefined);
                }}
                placeholder="例）明細3の領収書が添付されていません。再添付のうえ再申請してください。"
                rows={4}
              />
            </FormControl>
            <FormMessage />
          </FormField>
          <DialogFooter>
            <Button variant="outline" onClick={() => setRejectOpen(false)}>
              キャンセル
            </Button>
            <Button variant="warning" onClick={confirmReject}>
              <IconArrowBackUp className="h-4 w-4" aria-hidden />
              差戻しを確定
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </main>
  );
}
